#!/usr/bin/env node
import{mkdtempSync,rmSync,writeFileSync}from"node:fs";import{tmpdir}from"node:os";import{join}from"node:path";import{pathToFileURL}from"node:url";
const root=process.env.AEON_MEMORY_TS_BASELINE;if(!root)throw Error("AEON_MEMORY_TS_BASELINE required");const {OffloadStateManager}=await import(pathToFileURL(join(root,"src/offload/state-manager.ts")));const {createAfterToolCallHandler}=await import(pathToFileURL(join(root,"src/offload/hooks/after-tool-call.ts")));const {createBeforePromptBuildHandler}=await import(pathToFileURL(join(root,"src/offload/hooks/before-prompt-build.ts")));const {shouldForceL1}=await import(pathToFileURL(join(root,"src/offload/hooks/llm-output.ts")));
const d=mkdtempSync(join(tmpdir(),"aeon-memory-offload-state-"));const m=new OffloadStateManager();await m.init(d,"main","s1");const log={debug(){},info(){},warn(){},error(){}};const after=createAfterToolCallHandler(m,log,()=>10000,{forceTriggerThreshold:2},null);const counts=[];for(const e of[{toolName:"shell",toolCallId:"a",params:{cmd:"ls"},result:"ok"},{toolName:"shell",toolCallId:"a",params:{cmd:"ls"},result:"duplicate"},{toolName:"read",toolCallId:"hb",params:{path:"HEARTBEAT.md"},result:"x"},{toolName:"exec",toolCallId:"approval",params:{},result:{details:{status:"approval-pending"}}},{toolName:"shell",toolCallId:"b",params:{cmd:"pwd"},result:"ok"}]){await after(e,{});counts.push(m.getPendingCount());}const forced=[shouldForceL1(m,{forceTriggerThreshold:3}),shouldForceL1(m,{forceTriggerThreshold:2})];const before=createBeforePromptBuildHandler(m,log,()=>10000,{});const empty={messages:[]};await before(empty,{});m.setLastSessionKey("agent:main:memory-test-session-1");const internal={messages:[{role:"user",content:"unchanged"}]};await before(internal,{sessionKey:m.getLastSessionKey()});const taken=m.takePending(1).map(x=>x.toolCallId);m.setActiveMmd("001-task.mmd","node-1");m.setLastOffloadedToolCallId("a");m.setLastL2TriggerTime("2026-01-01T00:00:00Z");await m.save();const out={counts,forced,taken,processedA:m.isProcessed("a"),pending:m.getPendingCount(),empty,internal,state:m.getState()};rmSync(d,{recursive:true,force:true});writeFileSync(process.env.AEON_MEMORY_ORACLE_OUTPUT||new URL("./offload_state_oracle.json",import.meta.url).pathname,JSON.stringify(out,null,2)+"\n");
